def format_chunk(doc: Document, index: int) -> str:
    src   = doc.metadata.get("source", "unknown")
    page  = doc.metadata.get("page_number", "")
    label = f"[{index + 1}] Source: {src}" + (f", p.{page}" if page else "")
    return f"{label}\n{doc.page_content}"

def format_context(docs: list[Document]) -> str:
    return "\n\n---\n\n".join(format_chunk(doc, i) for i, doc in enumerate(docs))

