import re
from dataclasses import dataclass

@dataclass
class CitedAnswer:
    answer: str
    citations: list[dict]   # [{"index": 1, "source": "...", "page": 4}, ...]

def extract_citations(answer: str, docs: list[Document]) -> CitedAnswer:
    """Parse [N] references in the LLM answer and link them to source docs."""
    refs_found = sorted(set(int(m) for m in re.findall(r"\[(\d+)\]", answer)))
    citations  = []
    for n in refs_found:
        if 1 <= n <= len(docs):
            doc = docs[n - 1]
            citations.append({
                "index":  n,
                "source": doc.metadata.get("source", "?"),
                "page":   doc.metadata.get("page_number"),
            })
    return CitedAnswer(answer=answer, citations=citations)

