from langchain_core.prompts import ChatPromptTemplate
from langchain_openai import ChatOpenAI
from langchain_core.runnables import RunnablePassthrough

llm     = ChatOpenAI(model="gpt-4o-mini", streaming=True)
prompt  = ChatPromptTemplate.from_messages([
    ("system", "Answer using only the context below. Cite sources as [N].\n\nContext:\n{context}"),
    ("human",  "{question}"),
])

def format_docs(docs):
    return "\n\n---\n\n".join(
        f"[{i+1}] Source: {d.metadata.get('source', '?')}\n{d.page_content}"
        for i, d in enumerate(docs)
    )

chain = (
    {"context": retriever | format_docs, "question": RunnablePassthrough()}
    | prompt
    | llm
)

# Stream to stdout token by token
for chunk in chain.stream("What was Q3 2025 cloud revenue?"):
    print(chunk.content, end="", flush=True)
print()   # newline after streaming

